<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Falling Sand Cellular Automata Sandbox</title>
    <style>
        /* Global Reset and Dark Theme Setup */
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: #121212; /* Deep dark background */
            color: #e0e0e0;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
        }

        /* Main Container Layout */
        #sandbox-container {
            display: flex;
            flex-wrap: wrap;
            gap: 30px;
            max-width: 1200px;
            justify-content: center;
            margin-top: 20px;
        }

        /* Canvas Styling */
        #sand {
            border: 4px solid #333;
            background-color: #0d0d0d;
            box-shadow: 0 8px 16px rgba(0, 0, 0, 0.5);
            cursor: crosshair;
        }

        /* Material Selector Buttons (Material Design Look) */
        #material-selector {
            display: flex;
            flex-direction: column;
            gap: 10px;
            width: 280px; /* Fixed width for alignment */
        }

        .material-button {
            background-color: #333;
            color: #e0e0e0;
            border: none;
            padding: 12px 20px;
            text-align: left;
            cursor: pointer;
            transition: background-color 0.2s, box-shadow 0.2s;
            border-radius: 4px;
            box-shadow: 0 2px 5px rgba(0, 0, 0, 0.3);
        }

        /* Active/Selected Button State */
        .material-button.selected {
            background-color: #1e88e5; /* Primary blue accent */
            box-shadow: 0 4px 8px rgba(30, 136, 229, 0.4);
        }

        /* Hover State */
        .material-button:hover:not(.selected) {
            background-color: #444;
        }

        /* Clear Button Styling */
        #clear {
            width: 100%;
            padding: 12px 20px;
            margin-top: 15px;
